import{_ as d,r,o as c,c as p,a as e,b as t,t as s,d as o,w as l,e as h}from"./app-d223f2a5.js";const y={},w={id:"frontmatter-title-관련",tabindex:"-1"},m=e("a",{class:"header-anchor",href:"#frontmatter-title-관련","aria-hidden":"true"},"#",-1),g={class:"table-of-contents"},f=h('<hr><h2 id="project-7-part-three" tabindex="-1"><a class="header-anchor" href="#project-7-part-three" aria-hidden="true">#</a> Project 7, part three</h2><p>In this project we built the kind of app you’ll see in thousands of different iOS job interviews around the world: here’s a JSON feed, please parse it and show in a table view. Sure, our specific version was about one feed, but the concepts – fetching data, using <code>Codable</code>, rendering things into a web view, etc – are applicable anywhere.</p><p>But you’ve done more than just learn some new coding techniques. Michelle Obama once said “through my education, I didn&#39;t just develop skills, I didn&#39;t just develop the ability to learn, but I developed confidence.” And that’s true of you, too: each time you complete these projects you add another completed project to your résumé and you add another load of skills to your toolkit, but you’re also building the confidence that when you face a similar problem in the future you’ll realize you can look back on your work these last few days and have an instant refresher.</p><p>And it <em>is</em> a refresher. You see, you won’t remember the precise code you wrote today, and you might even forget class names like <code>JSONDecoder</code>. But that’s OK: being a skilled developer isn’t about memorizing classes or methods – it’s about knowing <em>concepts</em>. And if you’re able to apply the concepts from this project with some concepts from projects 2, 4, and 5 to make something entirely new, then you’re doing a great job.</p><p><strong>Today you should work through the wrap up chapter for project 7, complete its review, then work through all three of its challenges.</strong></p><h3 id="wrap-up" tabindex="-1"><a class="header-anchor" href="#wrap-up" aria-hidden="true">#</a> Wrap up</h3>',7),b={class:"hint-container details"},_=e("summary",null,"Wrap up",-1),v={href:"https://www.hackingwithswift.com/read/7/6/wrap-up",target:"_blank",rel:"noopener noreferrer"},k=e("p",null,"As your Swift skill increases, I hope you're starting to feel the balance of these projects move away from explaining the basics and toward presenting and dissecting code.",-1),j=e("p",null,[t("In this project you learned how to download JSON using Swift’s Data type, then use the Codable protocol to convert that data into Swift objects we defined. Working with JSON is something you're going to be doing time and time again in your Swift career, and you've cracked it in about an hour of work – while also learning about "),e("code",null,"UITabBarController"),t(", "),e("code",null,"UIStoryboard"),t(", and more.")],-1),I=e("p",null,"Good job!",-1),S=e("h4",{id:"review-what-you-learned",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#review-what-you-learned","aria-hidden":"true"},"#"),t(" Review what you learned")],-1),x=e("p",null,"Anyone can sit through a tutorial, but it takes actual work to remember what was taught. It’s my job to make sure you take as much from these tutorials as possible, so I’ve prepared a short review to help you check your learning.",-1),O={href:"https://www.hackingwithswift.com/review/hws/project-7-whitehouse-petitions",target:"_blank",rel:"noopener noreferrer"},T=h('<h4 id="challenge" tabindex="-1"><a class="header-anchor" href="#challenge" aria-hidden="true">#</a> Challenge</h4><p>One of the best ways to learn is to write your own code as often as possible, so here are three ways you should try extending this app to make sure you fully understand what’s going on:</p><ol><li>Add a Credits button to the top-right corner using <code>UIBarButtonItem</code>. When this is tapped, show an alert telling users the data comes from the We The People API of the Whitehouse.</li><li>Let users filter the petitions they see. This involves creating a second array of filtered items that contains only petitions matching a string the user entered. Use a <code>UIAlertController</code> with a text field to let them enter that string. This is a tough one, so I’ve included some hints below if you get stuck.</li><li>Experiment with the HTML – this isn’t a HTML or CSS tutorial, but you can find lots of resources online to give you enough knowledge to tinker with the layout a little.</li></ol><h4 id="hints" tabindex="-1"><a class="header-anchor" href="#hints" aria-hidden="true">#</a> Hints</h4><p>It is <em>vital</em> to your learning that you try the challenges above yourself, and not just for a handful of minutes before you give up.</p><p>Every time you try something wrong, you learn that it’s wrong and you’ll remember that it’s wrong. By the time you find the <em>correct</em> solution, you’ll remember it much more thoroughly, while also remembering a lot of the wrong turns you took.</p><p>This is what I mean by “there is no learning without struggle”: if something comes easily to you, it can go just as easily. But when you have to really mentally fight for something, it will stick much longer.</p><p>But if you’ve already worked hard at the challenges above and are still struggling to implement them, I’m going to write some hints below that should guide you to the correct answer.</p><p><strong>If you ignore me and read these hints without having spent at least 30 minutes trying the challenges above, the only person you’re cheating is yourself.</strong></p><p>Still here? OK. The second challenge here is to let users filter the petitions they see. To solve this you need to do a number of things:</p><ol><li>Have one property to store all petitions, and one to store filtered petitions. This means the user can filter the petitions several times and you don’t have to keep redownloading your JSON.</li><li>At first your filtered petitions array will be the same as the main petitions array, so just assign one to the other when your data is ready.</li><li>Your table view should load all its data from the filtered petitions array.</li><li>You’ll need a bar button item to show an alert controller that the user can type into.</li><li>Once that’s done, go through all the items in your petitions array, adding any you want to the filtered petition.</li></ol><p>The important part here is the last one: how do you decide whether a petition matches the user’s search? One option is to use <code>contains()</code> to check whether the petition title or body text contains the user’s search string – try it and see how you get on!</p>',12),B={class:"hint-container info"},N=e("p",{class:"hint-container-title"},"Wrap up - Additional",-1),A={href:"https://www.hackingwithswift.com/review/hws/project-7-whitehouse-petitions",target:"_blank",rel:"noopener noreferrer"},C=e("p",null,"Once you’re done, tell other people: you’ve built another great app for iOS, and you’ve learned more about parsing JSON, tab bar controllers, and more.",-1),W=e("p",null,"You should be proud of what you’ve accomplished – keep going!",-1);function J(a,P){const i=r("router-link"),n=r("ExternalLinkIcon"),u=r("YouTube");return c(),p("div",null,[e("h1",w,[m,t(" "+s(a.$frontmatter.title)+" 관련",1)]),e("blockquote",null,[e("p",null,s(a.$frontmatter.description),1)]),e("nav",g,[e("ul",null,[e("li",null,[o(i,{to:"#project-7-part-three"},{default:l(()=>[t("Project 7, part three")]),_:1}),e("ul",null,[e("li",null,[o(i,{to:"#wrap-up"},{default:l(()=>[t("Wrap up")]),_:1})])])])])]),f,e("details",b,[_,e("p",null,[e("a",v,[t("📎link"),o(n)])]),o(u,{id:"utUpNqglZGs"}),k,j,I,S,x,e("p",null,[e("a",O,[t("Click here to review what you learned in project 7."),o(n)])]),T]),e("div",B,[N,e("p",null,[e("a",A,[t("Review for Project 7: Whitehouse Petitions"),o(n)])])]),C,W])}const Y=d(y,[["render",J],["__file","35.html.vue"]]);export{Y as default};
